import React, { useState, useEffect, createContext, useContext } from 'react';
import axios from 'axios';
import { BrowserRouter as Router, Routes, Route, Link, useNavigate, Navigate } from 'react-router-dom';
import { API } from './api'

const HOST = window.location.hostname; // Automatically grabs your current AWS IP
const api = {
  user: API.user,
  account: API.account,
  tx: API.tx,
  loan: API.loan,
  report: API.report,
};

const AuthContext = createContext(null);

function AuthProvider({ children }) {
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (token) {
      api.user.get('/me', { headers: { Authorization: `Bearer ${token}` } })
        .then(res => { setUser(res.data); setLoading(false); })
        .catch(() => { logout(); setLoading(false); });
    } else {
      setLoading(false);
    }
  }, [token]);

  const login = (newToken) => {
    localStorage.setItem('token', newToken);
    setToken(newToken);
  };

  const logout = () => {
    localStorage.removeItem('token');
    setToken(null);
    setUser(null);
  };

  if (loading) return <div className="auth-container">Loading...</div>;

  return (
    <AuthContext.Provider value={{ token, user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

const useAuth = () => useContext(AuthContext);

// --- Components ---

function Navbar() {
  const { user, logout } = useAuth();
  return (
    <nav>
      <h2>NexusBank</h2>
      <ul>
        {user ? (
          <>
            <li><Link to="/">Dashboard</Link></li>
            <li><Link to="/transfer">Transfer</Link></li>
            <li><Link to="/loans">Loans</Link></li>
            <li><button onClick={logout} style={{padding: '6px 16px', background: 'transparent', border:'1px solid var(--primary)'}}>Logout</button></li>
          </>
        ) : (
          <>
            <li><Link to="/architecture">Architecture</Link></li>
            <li><Link to="/login">Login</Link></li>
            <li><Link to="/register">Register</Link></li>
          </>
        )}
      </ul>
    </nav>
  );
}

function Register() {
  const [form, setForm] = useState({ username: '', email: '', password: '' });
  const [err, setErr] = useState('');
  const navigate = useNavigate();

  const submit = async (e) => {
    e.preventDefault();
    try {
      await api.user.post(`/register`, form);
      // Create an initial account for them automatically
      const res = await api.user.post(`/login`, { username: form.username, password: form.password });
      const userId = res.data.user.id;
      // create default checking account with $1000 welcome bonus
      await api.account.post(`/accounts`, { userId, accountNumber: `CHK-${Date.now()}`, initialBalance: 1000 });
      navigate('/login');
    } catch (e) { setErr('Registration failed'); }
  };

  return (
    <div className="auth-container">
      <div className="glass-card auth-card">
        <h2>Open an Account</h2>
        {err && <div className="error-msg">{err}</div>}
        <form onSubmit={submit}>
          <div className="input-group">
            <label>Username</label>
            <input required onChange={e => setForm({...form, username: e.target.value})} />
          </div>
          <div className="input-group">
            <label>Email</label>
            <input type="email" required onChange={e => setForm({...form, email: e.target.value})} />
          </div>
          <div className="input-group">
            <label>Password</label>
            <input type="password" required onChange={e => setForm({...form, password: e.target.value})} />
          </div>
          <button type="submit">Sign Up</button>
        </form>
      </div>
    </div>
  );
}

