function Login() {
  const [form, setForm] = useState({ username: '', password: '' });
  const [err, setErr] = useState('');
  const { login } = useAuth();
  const navigate = useNavigate();

  const submit = async (e) => {
    e.preventDefault();
    try {
      const res = await api.user.post(`/login`, form);
      login(res.data.token);
      navigate('/');
    } catch (e) { setErr('Invalid credentials'); }
  };

  return (
    <div className="auth-container">
      <div className="glass-card auth-card">
        <h2>Welcome Back</h2>
        {err && <div className="error-msg">{err}</div>}
        <form onSubmit={submit}>
          <div className="input-group">
            <label>Username</label>
            <input required onChange={e => setForm({...form, username: e.target.value})} />
          </div>
          <div className="input-group">
            <label>Password</label>
            <input type="password" required onChange={e => setForm({...form, password: e.target.value})} />
          </div>
          <button type="submit">Log In</button>
        </form>
      </div>
    </div>
  );
}

function Dashboard() {
  const { user } = useAuth();
  const [accounts, setAccounts] = useState([]);
  const [txs, setTxs] = useState([]);

  useEffect(() => {
    if(!user) return;
    api.account.get(`/accounts/user/${user.id}`).then(res => {
      setAccounts(res.data);
      if(res.data.length > 0) {
        api.report.get(`/reports/transactions/${res.data[0].id}`).then(tr => setTxs(tr.data));
      }
    });
  }, [user]);

  return (
    <div>
      <h2>Dashboard</h2>
      <div className="grid">
        {accounts.map(acc => (
          <div key={acc.id} className="glass-card balance-card">
            <h3>Checking Account</h3>
            <p className="text-muted">{acc.account_number} (ID: {acc.id})</p>
            <div className="balance-amount">${parseFloat(acc.balance).toFixed(2)}</div>
          </div>
        ))}
      </div>
      
      <h3 style={{marginTop: '40px'}}>Recent Transactions</h3>
      <div className="glass-card table-container">
        <table>
          <thead>
            <tr>
              <th>ID</th>
              <th>Date</th>
              <th>From Acct</th>
              <th>To Acct</th>
              <th>Amount</th>
              <th>Status</th>
            </tr>
          </thead>
          <tbody>
            {txs.slice(0, 10).map(t => (
              <tr key={t.id}>
                <td>{t.id}</td>
                <td>{new Date(t.timestamp).toLocaleString()}</td>
                <td>{t.from_account_id}</td>
                <td>{t.to_account_id}</td>
                <td style={{color: accounts.map(a=>a.id).includes(t.from_account_id) ? 'var(--danger)' : 'var(--success)'}}>
                  {accounts.map(a=>a.id).includes(t.from_account_id) ? '-' : '+'}${parseFloat(t.amount).toFixed(2)}
                </td>
                <td>{t.status}</td>
              </tr>
            ))}
            {txs.length === 0 && <tr><td colSpan="6" style={{textAlign:'center', color:'var(--text-muted)'}}>No transactions found.</td></tr>}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function Transfer() {
  const { user } = useAuth();
  const [accounts, setAccounts] = useState([]);
  const [form, setForm] = useState({ fromAccountId: '', toAccountId: '', amount: '' });
  const [msg, setMsg] = useState({ text: '', type: '' });

  useEffect(() => {
    if(!user) return;
    api.account.get(`/accounts/user/${user.id}`).then(res => {
      setAccounts(res.data);
      if(res.data.length > 0) setForm(f => ({...f, fromAccountId: res.data[0].id}));
    });
  }, [user]);

  const submit = async (e) => {
    e.preventDefault();
    setMsg({text: '', type: ''});
    try {
      await api.tx.post(`/transfer`, form);
      setMsg({ text: 'Transfer successful!', type: 'success' });
      setForm({...form, toAccountId: '', amount: ''});
    } catch(err) {
      setMsg({ text: 'Transfer failed. Check balance or target account ID.', type: 'error' });
    }
  };

  return (
    <div className="glass-card" style={{maxWidth: '600px', margin: '0 auto'}}>
      <h2>Transfer Money</h2>
      {msg.text && <div className={msg.type === 'error' ? 'error-msg' : 'success-msg'}>{msg.text}</div>}
      <form onSubmit={submit}>
        <div className="input-group">
          <label>From Account</label>
          <select 
            value={form.fromAccountId} 
            onChange={e => setForm({...form, fromAccountId: e.target.value})}
            style={{width:'100%', padding:'12px', borderRadius:'8px', background:'rgba(0,0,0,0.2)', color:'white', border:'1px solid var(--glass-border)'}}
          >
            {accounts.map(a => <option key={a.id} value={a.id}>{a.account_number} - ${a.balance}</option>)}
          </select>
        </div>
        <div className="input-group">
          <label>To Account ID</label>
          <input required type="number" value={form.toAccountId} onChange={e => setForm({...form, toAccountId: e.target.value})} placeholder="e.g. 2" />
        </div>
        <div className="input-group">
          <label>Amount ($)</label>
          <input required type="number" step="0.01" value={form.amount} onChange={e => setForm({...form, amount: e.target.value})} placeholder="100.00" />
        </div>
        <button type="submit">Send Money</button>
      </form>
    </div>
  );
}

function Loans() {
  const { user } = useAuth();
  const [loans, setLoans] = useState([]);
  const [amount, setAmount] = useState('');
  const [msg, setMsg] = useState('');

  const fetchLoans = () => {
    api.loan.get(`/loans/user/${user.id}`).then(res => setLoans(res.data));
  };
  useEffect(() => { if(user) fetchLoans(); }, [user]);

  const submit = async (e) => {
    e.preventDefault();
    try {
      await api.loan.post(`/loans`, { userId: user.id, amount });
      setMsg('Loan approved!');
      setAmount('');
      fetchLoans();
    } catch(err) { setMsg('Loan request failed'); }
  };

  return (
    <div className="grid">
      <div className="glass-card">
        <h2>Apply for Loan</h2>
        {msg && <div className="success-msg">{msg}</div>}
        <form onSubmit={submit}>
          <div className="input-group">
            <label>Amount ($)</label>
            <input required type="number" value={amount} onChange={e=>setAmount(e.target.value)} />
          </div>
          <button type="submit">Apply</button>
        </form>
      </div>
      <div className="glass-card table-container">
        <h2>Your Loans</h2>
        <table>
          <thead><tr><th>ID</th><th>Amount</th><th>Status</th></tr></thead>
          <tbody>
            {loans.map(l => (
              <tr key={l.id}><td>{l.id}</td><td>${parseFloat(l.amount).toFixed(2)}</td><td><span style={{color:'var(--primary)'}}>{l.status}</span></td></tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

const Protected = ({ children }) => {
  const { user } = useAuth();
  return user ? children : <Navigate to="/architecture" />;
};

export default function App() {
  return (
    <AuthProvider>
      <Router>
        <div className="app-container">
          <Navbar />
          <Routes>
            <Route path="/login" element={<Login />} />
            <Route path="/register" element={<Register />} />
            <Route path="/architecture" element={<Architecture />} />
            <Route path="/" element={<Protected><Dashboard /></Protected>} />
            <Route path="/transfer" element={<Protected><Transfer /></Protected>} />
            <Route path="/loans" element={<Protected><Loans /></Protected>} />
          </Routes>
        </div>
      </Router>
    </AuthProvider>
  );
}
